function report = runWidelyLinearRenderedMatrix(options)
%RUNWIDELYLINEARRENDEREDMATRIX Rendered residual-camera bias controls.
%
% The imagery is rendered with the true moving camera. Matching then uses a
% camera whose principal point has a known constant bias along or perpendicular
% to dw/dZ. A constant line/sample bias has identity residual Jacobian and true
% residual mu=0; any fitted beta therefore diagnoses miscorrespondence rather
% than recovering the bias itself. Traceability: algo/main.tex Sec. 7.4-7.5,
% residual Mode A/B, Eqs. (86)-(95), and the camera-bias experiment.

arguments
    options.ConfigFile (1, 1) string = ""
    options.Display (1, 1) logical = true
end

root = fileparts(fileparts(mfilename("fullpath")));
oldPath = path;
addpath(fullfile(root, "src"));
cleanup = onCleanup(@() path(oldPath));
if strlength(options.ConfigFile) == 0
    options.ConfigFile = fullfile(root, "config", "synthetic", ...
        "pinhole_smoke_96_v1.json");
end

renderer = SyntheticPinholeRenderer.fromJson(options.ConfigFile);
pair = renderer.renderPair;
p = samplePixels(renderer.ImageSize);
trueGeometry = HeightSweepGeometry( ...
    renderer.ReferenceCamera, renderer.MovingCamera);
[t, kappa, derivativeValid] = trueGeometry.heightDerivative( ...
    p, renderer.TrueHeightMetres, DeltaHeight=0.5);
if ~all(derivativeValid)
    error("runWidelyLinearRenderedMatrix:InvalidDerivative", ...
        "Every camera-bias sample requires a valid dw/dZ.");
end
direction = median(t ./ kappa, 1);
direction = direction ./ norm(direction);
crossDirection = [-direction(2), direction(1)];
step = renderer.TargetMotionPerLabelPixels ./ median(kappa);
z = heightLabels(renderer.SearchRangeMetres, step);
levels = 2 ^ renderer.BitDepth - 1;

names = ["none", "along-0p25", "along-0p50", ...
    "cross-0p25", "cross-0p50", "mixed-0p35"];
bias = [0, 0; 0.25 .* direction; 0.50 .* direction; ...
    0.25 .* crossDirection; 0.50 .* crossDirection; ...
    0.35 .* (direction + crossDirection)];
cases = repmat(emptyCase, numel(names), 1);
rows = cell(numel(names), 18);
for k = 1:numel(names)
    km = renderer.MovingCamera.K;
    km(1, 3) = km(1, 3) + bias(k, 1);
    km(2, 3) = km(2, 3) + bias(k, 2);
    modelCamera = PinholeCamera(km, renderer.MovingCamera.R, ...
        renderer.MovingCamera.C, renderer.MovingCamera.ImageSize);
    modelGeometry = HeightSweepGeometry( ...
        renderer.ReferenceCamera, modelCamera);
    base = HeightCostCurve(modelGeometry, ...
        double(pair.ReferenceImage) ./ levels, ...
        double(pair.MovingImage) ./ levels, ...
        DerivativeSigma=1, IntegrationSigma=2, ...
        ReferenceValid=pair.ReferenceValid, ...
        MovingValid=pair.MovingValid);
    zncc = base.evaluate(p, z, Channels="Zncc", ...
        MinimumSupportFraction=0.95);
    curve = WidelyLinearHeightCurve(base);
    residual = curve.evaluate(p, z, MinimumSupportFraction=0.95);
    truthIndex = find(z == renderer.TrueHeightMetres, 1);
    truthValid = residual.FitValid(:, truthIndex);

    [wt, vt] = trueGeometry.warp(p, renderer.TrueHeightMetres);
    [wm, vm] = modelGeometry.warp(p, renderer.TrueHeightMetres);
    [tm, ~, vd] = modelGeometry.heightDerivative( ...
        p, renderer.TrueHeightMetres, DeltaHeight=0.5);
    du = wt - wm;
    [dz, ~, cross, decompositionValid] = ...
        HeightSweepGeometry.decomposeResidual(du, tm);
    geometryValid = vt & vm & vd & decompositionValid;

    center = ceil(size(p, 1) ./ 2);
    cases(k) = struct("Name", names(k), "BiasXY", bias(k, :), ...
        "Zncc", zncc, "Residual", residual, ...
        "TruthIndex", truthIndex, "DisplacementResidualXY", du, ...
        "EquivalentHeightResidualMetres", dz, ...
        "CrossTrackResidualXY", cross, ...
        "GeometryValid", geometryValid);
    rows(k, :) = {names(k), bias(k, 1), bias(k, 2), ...
        median(dz(geometryValid)), ...
        median(vecnorm(cross(geometryValid, :), 2, 2)), ...
        mean(truthValid), ...
        mean(residual.PhysicalValid(truthValid, truthIndex)), ...
        median(abs(residual.Mu(truthValid, truthIndex))), ...
        median(residual.DeltaCost(truthValid, truthIndex)), ...
        median(residual.Costs.Direct(truthValid, truthIndex)), ...
        median(residual.Costs.ConformalFit(truthValid, truthIndex)), ...
        median(residual.Costs.FullFit(truthValid, truthIndex)), ...
        median(residual.ConditionNumber(truthValid, truthIndex)), ...
        zncc.SelectedHeight.Zncc(center) - renderer.TrueHeightMetres, ...
        residual.SelectedHeight.Direct(center) ...
        - renderer.TrueHeightMetres, ...
        residual.SelectedHeight.ConformalFit(center) ...
        - renderer.TrueHeightMetres, ...
        residual.SelectedHeight.FullFit(center) ...
        - renderer.TrueHeightMetres, 0};
end

results = cell2table(rows, VariableNames=["Case", "BiasXPixel", ...
    "BiasYPixel", "MedianEquivalentHeightResidualMetres", ...
    "MedianCrossTrackResidualPixels", "TruthFitValidFraction", ...
    "TruthPhysicalValidFraction", "MedianTruthAbsMu", ...
    "MedianTruthDeltaCost", "MedianTruthDirectResidual", ...
    "MedianTruthConformalResidual", "MedianTruthFullResidual", ...
    "MedianTruthConditionNumber", "CenterZnccHeightErrorMetres", ...
    "CenterDirectHeightErrorMetres", ...
    "CenterConformalHeightErrorMetres", ...
    "CenterFullHeightErrorMetres", "TrueResidualMu"]);
report = struct("ConfigurationIdentifier", renderer.Identifier, ...
    "SamplePixels", p, "HeightLabelsMetres", z, ...
    "MedianObservabilityPixelsPerMetre", median(kappa), ...
    "LabelSpacingMetres", step, ...
    "HeightTrajectoryDirectionXY", direction, ...
    "CrossTrackDirectionXY", crossDirection, ...
    "Cases", cases, "Results", results, ...
    "TrueResidualJacobian", eye(2), "TrueResidualMu", 0, ...
    "BiasDefinition", ...
    "moving-camera principal-point [x,y]=[sample,line] offset in pixels", ...
    "Regularization", "none");

fprintf("Rendered widely linear camera-bias matrix: %d cases\n", ...
    height(results));
disp(results);
if options.Display
    showCurves(report, renderer.TrueHeightMetres);
end

clear cleanup
end

function c = emptyCase()
c = struct("Name", "", "BiasXY", nan(1, 2), ...
    "Zncc", struct, "Residual", struct, "TruthIndex", NaN, ...
    "DisplacementResidualXY", nan(0, 2), ...
    "EquivalentHeightResidualMetres", nan(0, 1), ...
    "CrossTrackResidualXY", nan(0, 2), ...
    "GeometryValid", false(0, 1));
end

function p = samplePixels(imageSize)
cx = (imageSize(2) + 1) ./ 2;
cy = (imageSize(1) + 1) ./ 2;
d = 0.18 .* [imageSize(2), imageSize(1)];
p = [cx - d(1), cy; cx, cy - d(2); cx, cy; ...
    cx, cy + d(2); cx + d(1), cy];
end

function z = heightLabels(range, step)
n0 = floor(abs(range(1)) ./ step);
n1 = floor(abs(range(2)) ./ step);
z = (-n0:n1) .* step;
end

function showCurves(report, truth)
figure(Name="Widely linear rendered camera-bias height curves");
tiledlayout(2, 3);
for k = 1:numel(report.Cases)
    nexttile;
    hold on;
    c = report.Cases(k);
    plot(report.HeightLabelsMetres, c.Zncc.Costs.Zncc(3, :), ...
        LineWidth=1);
    plot(report.HeightLabelsMetres, c.Residual.Costs.Direct(3, :), ...
        LineWidth=1);
    plot(report.HeightLabelsMetres, ...
        c.Residual.Costs.ConformalFit(3, :), LineWidth=1);
    plot(report.HeightLabelsMetres, c.Residual.Costs.FullFit(3, :), ...
        LineWidth=1);
    xline(truth, "--k", "Truth");
    grid on;
    xlabel("Elevation Z (m)");
    ylabel("Unregularized cost");
    title(c.Name);
end
legend(["ZNCC", "Direct", "Conformal fit", "Full fit"], ...
    Location="eastoutside");
end
